INSERT INTO `zgloszenia_naprawy` VALUES (1,'Telewizor nie włącza się','Telewizor突然 przestał się włączać. Dioda standby miga na czerwono, ale ekran pozostaje czarny. Próbowałem różnych gniazdek, ale bez skutku.','Samsung','UE55NU7092','',NULL,0,'normal','submitted','mazowieckie','Warszawa','00-123','ul. Długa 15/4',0,'[]',500.00,'2026-04-16 14:38:18.818102','2026-04-16 14:38:18.818120','2024-04-09 22:00:00.000000',NULL,2,1,NULL),(2,'iPhone 13 - zbita szybka','Telefon wypadł z ręki i szybka jest pęknięta. Ekran działa, ale pęknięcia utrudniają korzystanie. Czy jest możliwość wymiany na miejscu?','Apple','iPhone 13','',NULL,0,'high','offers_received','małopolskie','Kraków','30-001','',1,'[]',800.00,'2026-04-16 14:38:18.855624','2026-04-16 14:38:18.855641','2024-04-11 22:00:00.000000',NULL,3,2,NULL),(3,'Tablet nie ładuje baterii','Tablet przestał ładować baterię. Podłączam ładowarkę ale ikona ładowania się nie pojawia. Próbowano różnych ładowarek - ten sam efekt.','Samsung','Galaxy Tab S7','',NULL,0,'normal','in_progress','pomorskie','Gdańsk','80-001','',0,'[]',300.00,'2026-04-16 14:38:18.860908','2026-04-16 14:38:18.860938','2024-04-07 22:00:00.000000',NULL,4,3,NULL),(4,'TV OLED - zielony pasek na ekranie','Na ekranie telewizora pojawił się zielony pionowy pasek po prawej stronie. Problem występuje na wszystkich źródłach sygnału.','LG','OLED55C1','',NULL,1,'normal','offers_received','mazowieckie','Warszawa','00-123','',0,'[]',1000.00,'2026-04-16 14:38:18.867649','2026-04-16 19:30:04.758285','2024-04-14 22:00:00.000000',NULL,2,1,2),(5,'Xiaomi - ciągłe zawieszanie się','Telefon co chwilę się zawiesza, wymaga restartu. Problem zaczął się po aktualizacji systemu. Czy to wina oprogramowania czy sprzętu?','Xiaomi','Redmi Note 10 Pro','',NULL,0,'low','draft','małopolskie','Kraków','30-001','',1,'[]',200.00,'2026-04-16 14:38:18.874243','2026-04-16 14:38:18.874261',NULL,NULL,3,2,4),(6,'Naprawa telewizora Sony - ZAKOŃCZONE','Telewizor nie uruchamiał się poprawnie.','Sony','KD-55